import{c as a,Q as e,j as o,m as i}from"./chunks/framework.BXc4yaFE.js";const f=JSON.parse(`{"title":"The V4A Diff Format: How Codex CLI's apply_patch Actually Edits Your Code","description":"","frontmatter":{"url":"https://codex.danielvaughan.com/2026/03/31/codex-cli-apply-patch-v4a-diff-format/","date":"2026-05-09T00:00:00.000Z","source":"Codex Blog / Daniel Vaughan","tags":["tool-format","wire-format","post-training-investment","interoperability","Model-Harness-Fit"]},"headers":[],"relativePath":"research/ai-articles/scored/2026-05-09-v4a-diff-format-codex-post-training.md","filePath":"research/ai-articles/scored/2026-05-09-v4a-diff-format-codex-post-training.md","lastUpdated":1779796674000}`),r={name:"research/ai-articles/scored/2026-05-09-v4a-diff-format-codex-post-training.md"};function l(d,t,n,s,c,p){return e(),o("div",null,[...t[0]||(t[0]=[i('<h1 id="the-v4a-diff-format-how-codex-cli-s-apply-patch-actually-edits-your-code" tabindex="-1">The V4A Diff Format: How Codex CLI&#39;s apply_patch Actually Edits Your Code <a class="header-anchor" href="#the-v4a-diff-format-how-codex-cli-s-apply-patch-actually-edits-your-code" aria-label="Permalink to &quot;The V4A Diff Format: How Codex CLI&#39;s apply_patch Actually Edits Your Code&quot;">​</a></h1><p><strong>原始來源</strong>：<a href="https://codex.danielvaughan.com/2026/03/31/codex-cli-apply-patch-v4a-diff-format/" target="_blank" rel="noreferrer">https://codex.danielvaughan.com/2026/03/31/codex-cli-apply-patch-v4a-diff-format/</a><br><strong>作者</strong>：Daniel Vaughan（Codex Team）<br><strong>歸檔日期</strong>：2026-05-09</p><hr><h2 id="tl-dr" tabindex="-1">TL;DR <a class="header-anchor" href="#tl-dr" aria-label="Permalink to &quot;TL;DR&quot;">​</a></h2><p>V4A 是 Codex 的專有 diff 格式（context-anchored，以周圍代碼匹配而非絕對行號定位）。OpenAI 在 GPT-5.x 的 post-training 中投入「significant training effort」讓模型流暢生成 V4A。該格式現已成為 Codex models 的 byte-level 習慣；其他模型即使理論上可以採用 V4A，但缺乏訓練導致不可靠生成。Azure GPT-4.1 部署的失敗案例印證：移除 V4A 提示後，模型無法可靠產出。</p><hr><h2 id="核心主張" tabindex="-1">核心主張 <a class="header-anchor" href="#核心主張" aria-label="Permalink to &quot;核心主張&quot;">​</a></h2><ol><li><p><strong>Context-Anchored Diff 設計</strong></p><ul><li>解決問題：模型不可靠預測行號；全檔重寫浪費 tokens</li><li>V4A 方案：<code>@@</code> anchor 包含周圍代碼，harness 掃描匹配後 apply</li><li>Resilient to intervening edits and formatting variations</li></ul></li><li><p><strong>Post-Training 是實現的核心</strong></p><ul><li>GPT-5.x 專為 V4A 進行 post-training</li><li>模型不是簡單「理解 V4A 語法」，而是「習慣性自動生成 V4A」</li><li>Prompt cookbook 明確記錄「significant training effort」</li></ul></li><li><p><strong>格式鎖定帶來的不可移植性</strong></p><ul><li>理論：任何模型可採用 V4A（format-agnostic）</li><li>實際：Codex models 的 V4A 生成可靠；其他廠商模型在無 post-training 下表現不佳</li><li>Azure GPT-4.1（非 Codex CLI 特化部署）的故事：移除 V4A prompt → model can&#39;t reliably generate it</li></ul></li><li><p><strong>Harness 作為 Model 的隱形 Vocab</strong></p><ul><li>推文 @nicbstme 的「Tool Surface is Model&#39;s Vocabulary」的具體證據</li><li>V4A 不只是一個「工具」，而是模型 latent space 中的一個習慣固著點（attractor）</li></ul></li></ol><hr><h2 id="直接意涵" tabindex="-1">直接意涵 <a class="header-anchor" href="#直接意涵" aria-label="Permalink to &quot;直接意涵&quot;">​</a></h2><h3 id="cc-workspace-可行動性" tabindex="-1">cc-workspace 可行動性 <a class="header-anchor" href="#cc-workspace-可行動性" aria-label="Permalink to &quot;cc-workspace 可行動性&quot;">​</a></h3><ol><li><p><strong>Claude 的 String Replacement vs GPT 的 Patch：不可混淆</strong></p><ul><li>Claude Code 內建 <code>Edit</code> tool（search old_string → replace new_string）</li><li>即使有人提出「讓 Claude 用 V4A」的想法，缺乏 post-training 會導致品質下降</li><li><code>.claude/refs/harness-design.md</code> 應明確標記：「Edit tool shape is baked into Claude post-training；不應嘗試於 Claude Code 環境中強制 Codex 的 V4A 格式」</li></ul></li><li><p><strong>Multi-Harness Portability 的硬限制</strong></p><ul><li>此案例是 Model-Harness-Fit 最明確的 prove-by-contradiction</li><li>若要實現 multi-harness agent（如 Copilot CLI），無法「共用一套工具 schema」</li><li>Copilot 的解方：per-model tool inclusion（Codex 時代給 <code>apply_patch</code>，Claude 時代給 <code>Edit</code>）</li></ul></li><li><p><strong>新工具引入的 Post-Training 成本</strong></p><ul><li>若 cc-workspace 想引入新工具（如 SQL query tool），假設該工具需要 post-training 才能被模型可靠利用</li><li>工具可通過 prompt 介紹，但「byte-level 習慣」只能透過 post-training 來建立</li><li>實務建議：新工具應先在小 POC 驗證 Opus 4.7 的自然採用度，再廣泛部署</li></ul></li></ol><hr><h2 id="評分" tabindex="-1">評分 <a class="header-anchor" href="#評分" aria-label="Permalink to &quot;評分&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>理由</th></tr></thead><tbody><tr><td>A. Workspace 可行動性</td><td>8/10</td><td>清晰論述 tool-format 的不可移植性；直接影響 multi-harness 決策</td></tr><tr><td>B. 創新性</td><td>6/10</td><td>V4A 設計本身不新（已在 Codex 中部署多年）；此文的新意在「格式鎖定」論述</td></tr><tr><td>C. 證據品質</td><td>8/10</td><td>Azure 故事作為失敗案例；OpenAI 官方「significant training effort」的文件引用</td></tr><tr><td>D. 技術深度</td><td>8/10</td><td>V4A context-anchored 機制、anchor 匹配演算法清晰；缺乏對 post-training 內部機制的深入</td></tr><tr><td>E. 泛化性</td><td>7/10</td><td>原則（format specificity leads to overfitting）通用；V4A 本身 Codex 特化</td></tr><tr><td><strong>加權總分</strong></td><td><strong>7.5/10</strong></td><td>8×0.3 + 6×0.2 + 8×0.2 + 8×0.15 + 7×0.15 = 2.4+1.2+1.6+1.2+1.05 = 7.45</td></tr></tbody></table><p><strong>整合決策</strong>：Reference（納入 <code>.claude/refs/harness-design.md</code> 的「Tool Format Specificity」段落）</p><hr><h2 id="引用關聯" tabindex="-1">引用關聯 <a class="header-anchor" href="#引用關聯" aria-label="Permalink to &quot;引用關聯&quot;">​</a></h2><ul><li>推文 @nicbstme 2026-05-04：Tool Surface 和 wire format 為 post-training 的 byte-level 習慣</li><li><code>.claude/refs/harness-design.md</code>：Harness 架構模式</li><li>Cursor harness blog：per-model tool provisioning（apply_patch vs Edit）</li></ul>',19)])])}const u=a(r,[["render",l]]);export{f as __pageData,u as default};
